const { productById } = require('./products.js');

const ORDERS = [
  { id: 'o01', customerId: 'c1', items: [{ productId: 'p1', qty: 3 }, { productId: 'p2', qty: 1 }] },
  { id: 'o02', customerId: 'c2', items: [{ productId: 'p3', qty: 2 }] },
